package unverified;

import metadata.BehavioralDifference;
import metadata.DifferenceType;

import org.junit.jupiter.api.Test;

import static unverified.ClonePairGenericInvocationTestSupport.*;
import static org.junit.jupiter.api.Assertions.assertNotEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

class ClonePair12159DifferenceFindingTest {

    private final ClonePair12159 subject = new ClonePair12159();

    /**
     * Generated by Codex (GPT-5.4).
     * Difference type: side_effect.
     * Difference manifestation: the methods differ in observable side effects.
     */
    @Test
    @BehavioralDifference(DifferenceType.SIDE_EFFECT)
    void methodsDisagreeOnGeneratedInput() {
        InvocationOutcome method1Outcome = capture(values -> subject.method1((String) values[0], ((Integer) values[1]).intValue()), new Object[]{"a", 1});
        InvocationOutcome method2Outcome = capture(values -> subject.method2((String) values[0], ((Integer) values[1]).intValue()), new Object[]{"a", 1});
        String lineSeparator = System.lineSeparator();

        assertCoreOutcome(
            method1Outcome,
            "OK",
            "String(YQ==)",
            null,
            "java.lang.Object[][String(YQ==),Integer(1)]",
            "java.lang.Object[][String(YQ==),Integer(1)]"
        );
        assertCoreOutcome(
            method2Outcome,
            "OK",
            "String(YQ==)",
            null,
            "java.lang.Object[][String(YQ==),Integer(1)]",
            "java.lang.Object[][String(YQ==),Integer(1)]"
        );
        assertNotEquals(method1Outcome.stdout, method2Outcome.stdout);
        assertTextEquals("stdout", "", method1Outcome.stdout);
        assertTextEquals("stdout", "--1" + lineSeparator, method2Outcome.stdout);
        assertTextEquals("stderr", "", method1Outcome.stderr);
        assertTextEquals("stderr", "", method2Outcome.stderr);
    }
}
